import sys


def main():
    if len(sys.argv) < 2:
        print("Usage: python solution.py <measurements_file>")
        sys.exit(1)

    filepath = sys.argv[1]
    stats = {}  # station -> (min, max, sum, count)

    with open(filepath, "r", encoding="utf-8", buffering=65536) as f:
        for line in f:
            # Find semicolon without strip
            sep_idx = line.index(";", 0, len(line) - 1)  # ; is before final char
            station = line[:sep_idx]
            temp = float(line[sep_idx + 1:-1])  # -1 to skip newline

            if station in stats:
                mn, mx, total, count = stats[station]
                if temp < mn:
                    mn = temp
                if temp > mx:
                    mx = temp
                stats[station] = (mn, mx, total + temp, count + 1)
            else:
                stats[station] = (temp, temp, temp, 1)

    results = []
    for station, (mn, mx, total, count) in stats.items():
        results.append((station, mn, mx, total / count))

    results.sort(key=lambda x: x[0])

    print("{", end="")
    for i, (station, mn, mx, mean) in enumerate(results):
        if i:
            print(", ", end="")
        print(f"{station}={mn:.1f}/{mean:.1f}/{mx:.1f}", end="")
    print("}")


if __name__ == "__main__":
    main()

import sys


class Stats:
    __slots__ = ('mn', 'mx', 'total', 'count')

    def __init__(self, temp):
        self.mn = temp
        self.mx = temp
        self.total = temp
        self.count = 1


def parse_float_fast(s):
    """Fast custom float parser optimized for temperature data (-99.9 to 99.9)."""
    dot_idx = s.rfind('.')
    int_part = int(s[:dot_idx])
    dec_part = int(s[dot_idx + 1])

    if int_part < 0:
        return int_part - dec_part / 10.0
    else:
        return int_part + dec_part / 10.0


def main():
    if len(sys.argv) < 2:
        print("Usage: python solution.py <measurements_file>")
        sys.exit(1)

    filepath = sys.argv[1]
    stats = {}

    with open(filepath, "r", encoding="utf-8", buffering=262144) as f:
        for line in f:
            sep = line.find(";")
            station = line[:sep]
            temp = parse_float_fast(line[sep + 1:-1])

            s = stats.get(station)
            if s is None:
                stats[station] = Stats(temp)
            else:
                if temp < s.mn:
                    s.mn = temp
                elif temp > s.mx:
                    s.mx = temp
                s.total += temp
                s.count += 1

    # Sort stations alphabetically
    sorted_stations = sorted(stats.keys())

    print("{", end="")
    for i, station in enumerate(sorted_stations):
        if i:
            print(", ", end="")
        s = stats[station]
        mean = s.total / s.count
        print(f"{station}={s.mn:.1f}/{mean:.1f}/{s.mx:.1f}", end="")
    print("}")


if __name__ == "__main__":
    main()

import sys


class Stats:
    __slots__ = ('mn', 'mx', 'total', 'count')

    def __init__(self, temp_int):
        self.mn = temp_int
        self.mx = temp_int
        self.total = temp_int
        self.count = 1


def parse_temp_bytes(b):
    """Parse temperature from bytes, return as integer (tenths of degree)."""
    b = b[:-1]  # Remove newline
    dot_idx = b.rfind(b'.'[0])
    int_part = int(b[:dot_idx])
    dec_digit = b[dot_idx + 1] - ord(b'0')

    if int_part < 0:
        return int_part * 10 - dec_digit
    else:
        return int_part * 10 + dec_digit


def main():
    if len(sys.argv) < 2:
        print("Usage: python solution.py <measurements_file>")
        sys.exit(1)

    filepath = sys.argv[1]
    stats = {}

    with open(filepath, "rb", buffering=262144) as f:
        for line in f:
            sep = line.find(b";")
            station = line[:sep].decode('utf-8')
            temp_int = parse_temp_bytes(line[sep + 1:])

            try:
                s = stats[station]
                if temp_int < s.mn:
                    s.mn = temp_int
                elif temp_int > s.mx:
                    s.mx = temp_int
                s.total += temp_int
                s.count += 1
            except KeyError:
                stats[station] = Stats(temp_int)

    sorted_stations = sorted(stats.keys())

    print("{", end="")
    for i, station in enumerate(sorted_stations):
        if i:
            print(", ", end="")
        s = stats[station]
        mn = s.mn / 10.0
        mx = s.mx / 10.0
        mean = s.total / (s.count * 10.0)
        print(f"{station}={mn:.1f}/{mean:.1f}/{mx:.1f}", end="")
    print("}")


if __name__ == "__main__":
    main()

